using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private readonly ServiceRegistry _registry;

    public ServiceRegistryTests()
    {
        _registry = new ServiceRegistry();
    }

    [TestMethod]
    public void Register_AndResolve_ReturnsSameInstance()
    {
        var service = new FakeService();

        _registry.Register<IService>(service);
        var resolved = _registry.Resolve<IService>();

        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Resolve_Unregistered_ReturnsNull()
    {
        var result = _registry.Resolve<IService>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ResolveRequired_Unregistered_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(() => _registry.ResolveRequired<IService>());
    }

    [TestMethod]
    public void Register_Null_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _registry.Register<IService>(null!));
    }

    [TestMethod]
    public void Clear_RemovesAllRegistrations()
    {
        _registry.Register<IService>(new FakeService());
        _registry.Register<IAnotherService>(new AnotherFakeService());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<IService>());
        Assert.IsNull(_registry.Resolve<IAnotherService>());
        Assert.IsEmpty(_registry.GetAll());
    }

    [TestMethod]
    public void Remove_UnregistersService()
    {
        _registry.Register<IService>(new FakeService());

        _registry.Remove<IService>();

        Assert.IsNull(_registry.Resolve<IService>());
    }

    [TestMethod]
    public void GetAll_ReturnsAllRegistered()
    {
        var svc1 = new FakeService();
        var svc2 = new AnotherFakeService();

        _registry.Register<IService>(svc1);
        _registry.Register<IAnotherService>(svc2);

        var all = _registry.GetAll();

        Assert.HasCount(2, all);
        Assert.Contains(svc1, all);
        Assert.Contains(svc2, all);
    }

    [TestMethod]
    public void Register_SameType_OverwritesPrevious()
    {
        var first = new FakeService();
        var second = new FakeService();

        _registry.Register<IService>(first);
        _registry.Register<IService>(second);

        Assert.AreSame(second, _registry.Resolve<IService>());
    }

    private interface IService;
    private interface IAnotherService;
    private sealed class FakeService : IService;
    private sealed class AnotherFakeService : IAnotherService;
}

